// SWE - Auto-detect columns
const items = $input.all();
const validCandidates = [];

for (const item of items) {
  const row = item.json;

  // Find resume column
  let resumeUrl = '';
  for (const key of Object.keys(row)) {
    if (key.toLowerCase().includes('resume')) {
      resumeUrl = row[key];
      break;
    }
  }

  // Find email
  let email = '';
  for (const key of Object.keys(row)) {
    if (key.toLowerCase().includes('email')) {
      email = row[key];
      break;
    }
  }

  // Find name
  let name = '';
  for (const key of Object.keys(row)) {
    if (key.toLowerCase().includes('name')) {
      name = row[key];
      break;
    }
  }

  if (!resumeUrl || !email) continue;

  resumeUrl = resumeUrl.replace(/\s/g, '');
  let fileId = '';
  if (resumeUrl.includes('open?id=')) {
    fileId = resumeUrl.split('open?id=')[1].split('&')[0];
  }

  if (!fileId) continue;

  validCandidates.push({
    json: {
      name: name || 'Unknown',
      email: email.trim().toLowerCase(),
      role: 'Software Engineer',
      role_short: 'SWE',
      resumeUrl: resumeUrl,
      fileId: fileId,
      status: 'Pending',
      submittedAt: row['Timestamp'] || new Date().toISOString(),
      yearsExperience: row['Years of Experience'] || 'Not specified',
      skills: row['Technical Skills'] || 'Not specified',
      githubUrl: row['GitHub Profile Link'] || 'N/A'
    }
  });
}

return validCandidates;

