// Parse Groq/OpenAI response
const item = $input.item.json;
const candidateData = $('Prepare Resume for AI (SWE)').item.json;

let aiResult = {};
try {
  // Groq returns response in choices[0].message.content
  const rawText = item.choices[0].message.content;
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiResult = JSON.parse(cleaned);
} catch(e) {
  aiResult = {
    score: 50,
    classification: 'average',
    summary: 'AI evaluation could not be parsed. Manual review recommended.',
    strengths: ['Application submitted'],
    concerns: ['AI parsing issue: ' + e.message],
    interview_recommendation: 'Yes - Worth Exploring'
  };
}

const classification = (aiResult.classification || 'average').toLowerCase();

return [{
  json: {
    Name: candidateData.name || '',
    Email: candidateData.email || '',
    Role: candidateData.role || 'Software Engineer',
    'Submitted At': candidateData.submittedAt || '',
    'Resume URL': candidateData.resumeUrl || '',
    'AI Score': aiResult.score || 0,
    'AI Classification': classification,
    'AI Summary': aiResult.summary || '',
    'AI Strengths': (aiResult.strengths || []).join('; '),
    'AI Concerns': (aiResult.concerns || []).join('; '),
    'AI Recommendation': aiResult.interview_recommendation || '',
    Status: classification === 'strong' ? 'Interview' : classification === 'average' ? 'Manual Review' : 'Rejected',
    'Email Sent': 'No',
    'Email Sent At': '',
    'Processed At': new Date().toISOString()
  }
}];

